import{_ as a,o as t,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"23. Casual Employment","description":"","frontmatter":{"title":"23. Casual Employment","eba":"Health Allied & Managers Admin 2021-2025","topics":["employment","classifications"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/employment-types/23-casual-employment.md","filePath":"ebas/has-managers-admin/common-terms/employment-types/23-casual-employment.md"}'),s={name:"ebas/has-managers-admin/common-terms/employment-types/23-casual-employment.md"};function r(l,e,m,i,p,c){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_23-casual-employment" tabindex="-1">23. Casual Employment <a class="header-anchor" href="#_23-casual-employment" aria-label="Permalink to &quot;23. Casual Employment&quot;">​</a></h1><p><strong>23.1</strong> A person is a casual Employee if:</p><p><strong>(a)</strong> an offer of employment made by the Employer to the person is made on the basis that the Employer makes no firm advance commitment to continuing and indefinite work according to an agreed pattern of work for the person; and</p><p><strong>(b)</strong> the person accepts the offer on that basis; and</p><p><strong>(c)</strong> the person is an employee as a result of that acceptance.</p><p><strong>23.2</strong> Casual Employees will be paid an amount equal to 1/38th of the weekly wage rate for their classification per hour plus:</p><p><strong>(a)</strong> a 25% loading for work performed on week days;</p><p><strong>(b)</strong> a 75% loading for work performed on Saturdays, Sundays and Public Holidays.</p><p><strong>23.3</strong> A casual Employee will be entitled to receive the appropriate uniform and other allowances.</p><p><strong>23.4</strong> The provisions of:</p><p><strong>(a)</strong> <a href="/eba/ebas/has-managers-admin/common-terms/employment-types/25-fixed-term-employment.html">clause 25</a> of Section 2 and <a href="/eba/ebas/has-managers-admin/common-terms/preliminary/10-best-practice-employment-commitment.html">clause 10</a> of Section 3 (Overtime)</p><p><strong>(b)</strong> <a href="/eba/ebas/has-managers-admin/common-terms/leave/69-public-holidays.html">clause 69</a> of Section 1 (Public Holidays);</p><p>PART C – TYPES OF EMPLOYMENT AND TERMINATION OF EMPLOYMENT</p><p><strong>(c)</strong> <a href="/eba/ebas/has-managers-admin/common-terms/leave/53-annual-leave.html">clause 53</a> of Section 1 (Annual Leave);</p><p><strong>(d)</strong> <a href="/eba/ebas/has-managers-admin/common-terms/leave/55-personal-leave.html">clause 55</a> of Section 1 (Personal/Carer’s Leave);</p><p><strong>(e)</strong> <a href="/eba/ebas/has-managers-admin/common-terms/leave/56-compassionate-leave.html">clause 56</a> of Section 1 (Compassionate Leave);</p><p><strong>(f)</strong> <a href="/eba/ebas/has-managers-admin/common-terms/leave/59-parental-leave.html">clause 59</a> of Section 1 (Parental Leave); and any other clause which expressly states that it does not apply to casual Employees will not apply to casual Employees, except where the relevant clause expressly provides entitlements for casual Employees.</p><p><strong>23.5</strong> The 25% loading referred to in subclause 23.2(a) and one third of the 75% loading referred to in subclause 23.2(b) (i.e. 25% of the amount equal to 1/38th of the weekly wage rate) (Casual Loading) are paid instead of the paid entitlements of full-time and part-time Employees whether arising under the provisions referred to in subclause 23.4 or under the NES. In the event that an Employee receives the Casual Loading in respect of a period in which they are subsequently determined to be a full-time or part-time Employee, the Employer will be entitled to set off the amount of the Casual Loading against any amounts owing for paid entitlements whether arising under the provisions referred to in subclause 23.4 or under the NES.</p><p>Plain language terms: casual.</p>',19)])])}const u=a(s,[["render",r]]);export{d as __pageData,u as default};
